链接
这个区间dp的状态设计很巧妙。dp[i][j] 表示用  的长度为  的前缀组成  的子串方案数。
然后转移就是普通的区间dp的转移了。
初始化的时候根据题意，第一个放进去的也是算两种方法的，所以都初始化为 。
#include &lt;bits/stdc++.h&gt;using namespace std;using ll = long long;const int maxn = 3e3 + 5;const ll mod = 998244353;ll dp[maxn][maxn];void solve() {    string s, t;    cin &gt;&gt; s &gt;&gt; t;    int m = s.length(), n = t.length();    for (int i = 0; i &lt; n; ++i)        dp[i][i] = 2 * (s[0] == t[i]);    for (int i = n; i &lt; m; ++i) dp[i][i] = 2;    for (int len = 2; len &lt;= m; ++len) {        for (int i = 0; i &lt;= m - len; ++i) {            int j = i + len - 1;            if (i &gt;= n || t[i] == s[len - 1])                (dp[i][j] += dp[i + 1][j]) %= mod;            if (j &gt;= n || t[j] == s[len - 1])                (dp[i][j] += dp[i][j - 1]) %= mod;        }    }    ll ans = 0;    for (int i = n - 1; i &lt; m; ++i)        (ans += dp[0][i]) %= mod;    cout &lt;&lt; ans &lt;&lt; endl;}int main() {    ios::sync_with_stdio(false);    cin.tie(nullptr);    int T = 1;    // cin &gt;&gt; T;    while (T--) {        solve();    }}

链接
先考虑怎样的图可以染色或者不能染色。容易发现，1 和 3 不能相邻，它们其实是等价的。那么能染色的必要条件就是所有的子图都是二分图。此外，每个二分图都取左部或者右部之一，顶点数量之和需要正好等于 。
于是这个问题转化成了普通的背包 dp，转移的时候记录一下就好了。
#include &lt;bits/stdc++.h&gt;using namespace std;using ll = long long;#define pb push_back#define endl '\n'using ll = long long;using pii = pair&lt;int, int&gt;;const int maxn = 5e3 + 5;vector&lt;int&gt; g[maxn];int vis[maxn], cnt, col[maxn];vector&lt;pii&gt; color;int dp[maxn][maxn];bool ok;void dfs(int u, int f, bool flag) {    if (!ok) return;    if (vis[u] == -1) {        vis[u] = cnt;        col[u] = flag;    } else if (col[u] == flag) {    	return;    } else {        ok = false;        return;    }    if (!flag) color[cnt].first++;    else color[cnt].second++;    for (auto v : g[u]) {        if (v == f) continue;        dfs(v, u, !flag);    }}void solve() {    int n, m;    cin &gt;&gt; n &gt;&gt; m;    int n1, n2, n3;    cin &gt;&gt; n1 &gt;&gt; n2 &gt;&gt; n3;    for (int i = 1, u, v; i &lt;= m; ++i) {        cin &gt;&gt; u &gt;&gt; v;        g[u].pb(v), g[v].pb(u);    }    memset(vis, -1, sizeof(vis));    ok = true;    color.pb({ 0, 0 });    for (int i = 1; i &lt;= n; ++i) {        if (vis[i] == -1 &amp;&amp; ok) {        	cnt++;            color.pb({ 0, 0 });            dfs(i, 0, 0);        }    }    if (!ok) {        cout &lt;&lt; "NO\n" &lt;&lt; endl;        return;    }    dp[0][0] = 1;    for (int i = 1; i &lt;= cnt; ++i) {        for (int j = 0; j &lt;= n; ++j) {            auto [L, R] = color[i];            if (j &gt;= L &amp;&amp; dp[i - 1][j - L]) {                dp[i][j] = -1;            }            if (j &gt;= R &amp;&amp; dp[i - 1][j - R]) {                dp[i][j] = 1;            }        }    }    if (!dp[cnt][n2]) {        cout &lt;&lt; "NO\n" &lt;&lt; endl;        return;    }    cout &lt;&lt; "YES\n";    vector&lt;int&gt; ans(n + 1);    vector&lt;int&gt; chk(cnt + 1);    int tot = n2;    for (int i = cnt; i &gt;= 1; --i) {    	auto [L, R] = color[i];    	if (dp[i][tot] == 1) {    		tot -= R;    		chk[i] = 1;    	} else {    		tot -= L;    		chk[i] = 0;    	}    }    for (int i = 1; i &lt;= n; ++i) {    	int cur = vis[i];     	ans[i] = (chk[cur] == col[i]) + 1;    	if (ans[i] == 1) {    		if (n1) n1--;    		else ans[i] = 3;    	}    }    for (int i = 1; i &lt;= n; ++i)        cout &lt;&lt; ans[i];}int main() {    ios::sync_with_stdio(false);    cin.tie(nullptr);    int T = 1;    // cin &gt;&gt; T;    while (T--) {        solve();    }}

链接
求从  到  的最短路径的数量。
显然应该从  走到  再走到 ，容易证明这样走是最优的。那么现在只需要把两段的最短路径数量分别求出来就行了。
最短路径数量随便排列组合算一下就好了。
#include &lt;bits/stdc++.h&gt;using namespace std;using ll = long long;const int maxn = 1e5 + 5;const ll mod = 998244353;ll qpow(ll b, ll k) {    ll ret = 1;    while (k) {        if (k &amp; 1) ret = ret * b % mod;        b = b * b % mod;        k /= 2;    }    return ret;}vector&lt;ll&gt; prime;ll fact[maxn], ifact[maxn];void init_fact(int n) {    fact[0] = 1;    for (int i = 1; i &lt;= n; ++i)        fact[i] = fact[i - 1] * i % mod;    ifact[n] = qpow(fact[n], mod - 2);    for (int i = n - 1; i &gt;= 0; --i)        ifact[i] = ifact[i + 1] * (i + 1) % mod;}void solve() {    ll x, y;    cin &gt;&gt; x &gt;&gt; y;    ll ans = 1;    ll g = __gcd(x, y);    x /= g, y /= g;    vector&lt;int&gt; vx, vy;    for (auto p : prime) {        int cntx = 0, cnty = 0;        while (x % p == 0) {            x /= p;            cntx++;        }        while (y % p == 0) {            y /= p;            cnty++;        }        vx.push_back(cntx);        vy.push_back(cnty);    }    ans = ans * fact[accumulate(vx.begin(), vx.end(), 0)] % mod;    ans = ans * fact[accumulate(vy.begin(), vy.end(), 0)] % mod;    for (auto i : vx) ans = ans * ifact[i] % mod;    for (auto i : vy) ans = ans * ifact[i] % mod;    cout &lt;&lt; ans &lt;&lt; endl;}int main() {    ios::sync_with_stdio(false);    cin.tie(nullptr);    ll n;    cin &gt;&gt; n;    ll x = n;    for (ll i = 2; i * i &lt;= x; ++i) {        if (x % i != 0) continue;        prime.push_back(i);        while (x % i == 0) x /= i;    }    if (x != 1) prime.push_back(x);    init_fact(2333);    int q;    cin &gt;&gt; q;    while (q--) {        solve();    }}

Codeforces Round 862 (Div. 2)
先简单写一下 A-E 的题解。
A异或的经典性质：。
B显然要把字典序最小的那个字母放到最前面。
如果这个字母出现了很多次，那么应该选择最后一次出现的位置。这也很容易证明。
C联立以后计算一下就行了。
比赛的时候爆了一次 int。
#include &lt;bits/stdc++.h&gt;using namespace std;using ll = long long;#define pb push_back#define endl '\n'using ll = long long;using pii = pair&lt;int, int&gt;;const int maxn = 2e5 + 5;const ll mod = 998244353;const int dx[4] = { -1, 0, 1, 0 };const int dy[4] = { 0, -1, 0, 1 };const double eps = 1e-6;void solve() {    int n, m;    cin &gt;&gt; n &gt;&gt; m;    vector&lt;int&gt; K(n);    for (int i = 0; i &lt; n; ++i) {        cin &gt;&gt; K[i];    }    vector&lt;tuple&lt;ll, ll, ll&gt;&gt; parabolas(m);    for (int i = 0, a, b, c; i &lt; m; ++i) {        cin &gt;&gt; a &gt;&gt; b &gt;&gt; c;        parabolas[i] = {a, b, c};    }    sort(K.begin(), K.end());    for (auto [A, B, C] : parabolas) {        if (C &lt;= 0) {            cout &lt;&lt; "NO" &lt;&lt; endl;        } else {            ll sAC = sqrt(4.0 * A * C);            if (sAC * sAC == A * C * 4) sAC--;            auto it = lower_bound(K.begin(), K.end(), B - sAC);            if (it == K.end()) {                 cout &lt;&lt; "NO" &lt;&lt; endl;            } else if (*it &gt; B + sAC) {                cout &lt;&lt; "NO" &lt;&lt; endl;            } else {                cout &lt;&lt; "YES\n" &lt;&lt; (*it) &lt;&lt; endl;            }        }    }    cout &lt;&lt; endl;}int main() {    ios::sync_with_stdio(false);    cin.tie(nullptr);    int T = 1;    cin &gt;&gt; T;    while (T--) {        solve();    }}

D容易发现，当  从大到小变化时，点会一层一层的加进连通块里。
然后这个  的最大值是树的直径，所以点的层数应该以直径为标准进行统计。
最后模拟这个加点的过程即可。
#include &lt;bits/stdc++.h&gt;using namespace std;using ll = long long;#define pb push_back#define endl '\n'using ll = long long;using pii = pair&lt;int, int&gt;;const int maxn = 1e5 + 5;const ll mod = 998244353;const int dx[4] = { -1, 0, 1, 0 };const int dy[4] = { 0, -1, 0, 1 };vector&lt;int&gt; g[maxn];int dep[maxn], h[maxn];int mxdep, root;void dfs0(int u, int f) {    dep[u] = dep[f] + 1;    for (auto v : g[u]) {        if (v == f) continue;        dfs0(v, u);    }    if (dep[u] &gt;= mxdep) {        mxdep = dep[u];        root = u;    }}void dfs(int u, int f) {    dep[u] = dep[f] + 1;    for (auto v : g[u]) {        if (v == f) continue;        dfs(v, u);    }    h[u] = max(h[u], dep[u]);}void solve() {    int n;    cin &gt;&gt; n;    for (int i = 1, u, v; i &lt; n; ++i) {        cin &gt;&gt; u &gt;&gt; v;        g[u].pb(v), g[v].pb(u);    }    dep[0] = -1;    mxdep = 0;    dfs0(1, 0);    int r = root;    dfs0(root, 0);    dfs(r, 0);    dfs(root, 0);    vector&lt;int&gt; cnt(n + 5, 0);    for (int i = 1; i &lt;= n; ++i) {        cnt[h[i]]++;    }    cnt[mxdep]--;    vector&lt;int&gt; ans(n + 5, n);    for (int k = mxdep; k &gt;= 1; --k) {        ans[k] = ans[k + 1] - cnt[k];    }    for (int i = 1; i &lt;= n; ++i) {        cout &lt;&lt; ans[i] &lt;&lt; " \n"[i == n];    }}int main() {    ios::sync_with_stdio(false);    cin.tie(nullptr);    int T = 1;    // cin &gt;&gt; T;    while (T--) {        solve();    }}

E比赛的时候时间不够了，想写个 dsu on tree 试一下，可惜最后还是没写完。
这题的正解其实很简单，考虑整棵树的 MAD，如果这个数出现的次数不是 ，那么不管断哪条边都不会改变答案。如果出现次数正好是 ，那么只有这两个点之间的链被断开的时候，答案才会变化。所以先把链提取出来，然后在链上面按顺序算过去就行了。
如果没有观察到这个性质，用 dsu on tree 其实也是能做的。但是会跑的慢一些。
#include &lt;bits/stdc++.h&gt;using namespace std;using ll = long long;#define pb push_back#define endl '\n'using ll = long long;using pii = pair&lt;int, int&gt;;const int maxn = 1e5 + 5;const ll mod = 998244353;const int dx[4] = { -1, 0, 1, 0 };const int dy[4] = { 0, -1, 0, 1 };vector&lt;pii&gt; g[maxn];int w[maxn];map&lt;int, int&gt; subtree, total;set&lt;int&gt; smad, tmad;int sz[maxn], big[maxn];int L[maxn], R[maxn], dfn, node[maxn];int ans[maxn], edge_id[maxn];void dfs0(int u, int f) {    L[u] = ++dfn;    node[dfn] = u;    sz[u] = 1;    for (auto [v, e] : g[u]) {        if (v == f) continue;        edge_id[v] = e;        dfs0(v, u);        sz[u] += sz[v];        if (!big[u] || sz[big[u]] &lt; sz[v])            big[u] = v;    }    R[u] = dfn;}void add(int x) {    subtree[x]++;    if (subtree[x] == 2)        smad.insert(x);    total[x]--;    if (total[x] == 1)        tmad.erase(x);}void del(int x) {    total[x]++;    if (total[x] == 2)        tmad.insert(x);    subtree[x]--;    if (subtree[x] == 1)        smad.erase(x);}int MAD() {    int mx = 0;    if (!smad.empty()) {        mx = max(mx, *smad.rbegin());    }    if (!tmad.empty()) {        mx = max(mx, *tmad.rbegin());    }    return mx;}void dfs1(int u, int f, bool keep) {    for (auto [v, e] : g[u]) {        if (v == f || v == big[u])            continue;        dfs1(v, u, false);    }    if (big[u]) {        dfs1(big[u], u, true);    }    for (auto [v, e] : g[u]) {        if (v == f || v == big[u])            continue;        for (int i = L[v]; i &lt;= R[v]; i++) {            add(w[node[i]]);        }    }    add(w[u]);    ans[edge_id[u]] = MAD();    if (keep == false) {        for (int i = L[u]; i &lt;= R[u]; i++) {            del(w[node[i]]);        }    }}void solve() {    int n;    cin &gt;&gt; n;    for (int i = 1, u, v; i &lt; n; ++i) {        cin &gt;&gt; u &gt;&gt; v;        g[v].pb({ u, i });        g[u].pb({ v, i });    }    for (int i = 1; i &lt;= n; ++i) {        cin &gt;&gt; w[i];        total[w[i]]++;        if (total[w[i]] == 2)            tmad.insert(w[i]);    }    dfs0(1, 0);    dfs1(1, 0, false);    for (int i = 1; i &lt; n; ++i) {        cout &lt;&lt; ans[i] &lt;&lt; endl;    }}int main() {    ios::sync_with_stdio(false);    cin.tie(nullptr);    int T = 1;    // cin &gt;&gt; T;    while (T--) {        solve();    }}

不加任何优化的 dsu on tree 跑了 900ms 多，几乎是贴着时限过的。最好还是优化一下，比如先离散化一下，省掉两个 map，就会和正解一样快了。
这是因为正解的做法是  的，而原来的 dsu on tree 的复杂度是 ，因为会有  级别的点涉及到修改数据结构的操作，而修改的代价是 。但是修改数据结构的绝大部分代价在于 map 上，所以把这部分优化掉的效果是很明显的。
优化后（358ms）：
#include &lt;bits/stdc++.h&gt;using namespace std;using ll = long long;#define pb push_back#define endl '\n'using ll = long long;using pii = pair&lt;int, int&gt;;const int maxn = 1e5 + 5;const ll mod = 998244353;const int dx[4] = { -1, 0, 1, 0 };const int dy[4] = { 0, -1, 0, 1 };vector&lt;pii&gt; g[maxn];int w[maxn];int subtree[maxn], total[maxn];set&lt;int&gt; smad, tmad;int sz[maxn], big[maxn];int L[maxn], R[maxn], dfn, node[maxn];int ans[maxn], edge_id[maxn];void dfs0(int u, int f) {    L[u] = ++dfn;    node[dfn] = u;    sz[u] = 1;    for (auto [v, e] : g[u]) {        if (v == f) continue;        edge_id[v] = e;        dfs0(v, u);        sz[u] += sz[v];        if (!big[u] || sz[big[u]] &lt; sz[v])            big[u] = v;    }    R[u] = dfn;}void add(int x) {    subtree[x]++;    if (subtree[x] == 2)        smad.insert(x);    total[x]--;    if (total[x] == 1)        tmad.erase(x);}void del(int x) {    total[x]++;    if (total[x] == 2)        tmad.insert(x);    subtree[x]--;    if (subtree[x] == 1)        smad.erase(x);}int MAD() {    int mx = 0;    if (!smad.empty()) {        mx = max(mx, *smad.rbegin());    }    if (!tmad.empty()) {        mx = max(mx, *tmad.rbegin());    }    return mx;}void dfs1(int u, int f, bool keep) {    for (auto [v, e] : g[u]) {        if (v == f || v == big[u])            continue;        dfs1(v, u, false);    }    if (big[u]) {        dfs1(big[u], u, true);    }    for (auto [v, e] : g[u]) {        if (v == f || v == big[u])            continue;        for (int i = L[v]; i &lt;= R[v]; i++) {            add(w[node[i]]);        }    }    add(w[u]);    ans[edge_id[u]] = MAD();    if (keep == false) {        for (int i = L[u]; i &lt;= R[u]; i++) {            del(w[node[i]]);        }    }}void solve() {    int n;    cin &gt;&gt; n;    for (int i = 1, u, v; i &lt; n; ++i) {        cin &gt;&gt; u &gt;&gt; v;        g[v].pb({ u, i });        g[u].pb({ v, i });    }    vector&lt;int&gt; all;    for (int i = 1; i &lt;= n; ++i) {        cin &gt;&gt; w[i];        all.pb(w[i]);    }    sort(all.begin(), all.end());    all.erase(unique(all.begin(), all.end()), all.end());    unordered_map&lt;int, int&gt; wmap;    for (int i = 0; i &lt; all.size(); ++i)        wmap[all[i]] = i + 1;    for (int i = 1; i &lt;= n; ++i) {        w[i] = wmap[w[i]];        total[w[i]]++;        if (total[w[i]] == 2)            tmad.insert(w[i]);    }    dfs0(1, 0);    dfs1(1, 0, false);    for (int i = 1; i &lt; n; ++i) {        if (ans[i]) ans[i] = all[ans[i] - 1];        cout &lt;&lt; ans[i] &lt;&lt; endl;    }}int main() {    ios::sync_with_stdio(false);    cin.tie(nullptr);    int T = 1;    // cin &gt;&gt; T;    while (T--) {        solve();    }}
